// Walk Flint's TPS-mail inbox and emit one item per .json mail file.
// Single Code node replaces the older ls + Split + Read + Parse chain
// because (a) it's atomic — no node-version drift to chase, (b) it's
// portable to any maildir-shaped source by changing the path, (c) n8n's
// ExecuteCommand stdout-as-string didn't play nicely with Item Lists
// when filenames had spaces or odd chars.
//
// Each emitted item: { mail: <parsed JSON>, _file: <basename> }.
const fs = require('fs');
const path = require('path');
const INBOX = '/Users/squeued/.tps/mail/flint/new';

let entries;
try {
  entries = fs.readdirSync(INBOX);
} catch (err) {
  // Inbox missing is not an error condition — first ever run on a fresh
  // box can legitimately have no inbox yet.
  if (err.code === 'ENOENT') return [];
  throw err;
}

const items = [];
for (const f of entries) {
  if (!f.endsWith('.json')) continue;
  const full = path.join(INBOX, f);
  try {
    const content = fs.readFileSync(full, 'utf8');
    const mail = JSON.parse(content);
    items.push({ json: { mail, _file: f } });
  } catch (err) {
    // Skip malformed mail files — they'll surface in a later sweep when
    // the file is rewritten cleanly, or get cleaned up via the gc loop.
    continue;
  }
}
return items;

// Filter to K&S only. Could use n8n's Filter node, but the
// containedInList operator's rightValue parsing varies across n8n
// versions — easier to keep the predicate explicit here.
const KS = new Set(['kern', 'sherlock']);
return $input.all().filter((item) => KS.has(item.json.mail?.from));

// Dedup: skip mails we've already written to Flair.
// Uses workflow static data as a compact processed-id set so we don't
// re-write a memory every 5-min tick for files that haven't been drained
// from flint/new/ yet.
const staticData = $getWorkflowStaticData('global');
staticData.processedIds = staticData.processedIds || {};

const out = [];
for (const item of $input.all()) {
  const mail = item.json.mail;
  const id = mail.id;
  if (!id || staticData.processedIds[id]) continue;
  staticData.processedIds[id] = new Date().toISOString();
  // Trim if it gets large — keep last 4000 of the most recent 5000.
  const ids = Object.keys(staticData.processedIds);
  if (ids.length > 5000) {
    const sortedByTime = ids.sort((a, b) => (staticData.processedIds[a] < staticData.processedIds[b] ? -1 : 1));
    for (const old of sortedByTime.slice(0, 1000)) delete staticData.processedIds[old];
  }
  out.push({ json: { mail } });
}
return out;

// Format the memory before write: build content, derive tags, set subject.
for (const item of $input.all()) {
  const m = item.json.mail;
  const ts = m.timestamp || new Date().toISOString();
  const day = ts.slice(0, 10);
  const prMatch = (m.body || '').match(/#(\d{2,5})/);
  const prTag = prMatch ? `pr:${prMatch[1]}` : null;
  const content = [
    `${m.from} review note (${day}):`,
    '',
    m.body,
  ].join('\n');
  const tags = [
    'source:tps-mail',
    'kind:review',
    `agent:${m.from}`,
    `date:${day}`,
    prTag,
  ].filter(Boolean).join(', ');
  const subject = prTag ? `pr-${prMatch[1]}` : `${m.from}-${day}`;
  item.json = {
    ...item.json,
    content,
    tags,
    subject,
  };
}
return $input.all();
